// Enrich and normalize the incoming FraudShield payload
const body = $input.first().json.body || $input.first().json;
const now  = new Date().toISOString();

const tierColors = {
  CRITICAL: '#dc3545',
  HIGH:     '#fd7e14',
  MEDIUM:   '#ffc107',
  LOW:      '#28a745'
};

return [{
  json: {
    incident_id:       `FS-${Date.now()}`,
    logged_at:         now,
    tier:              body.tier              || 'UNKNOWN',
    risk_score:        body.risk_score        || 0,
    verdict:           body.verdict           || 'UNKNOWN',
    outlook_action:    body.outlook_action    || 'REVIEW',
    prediction_id:     body.prediction_id     || null,
    ai_generated_prob: body.ai_generated_probability || 0,
    roberta_prob:      body.roberta_phishing_prob     || 0,
    top_indicators:    body.top_indicators    || [],
    header_flags:      body.header_flags      || [],
    injection_score:   body.injection_score   || 0,
    email_preview:     body.email_preview     || '',
    source:            body.source            || 'outlook_plugin',
    tier_color:        tierColors[body.tier]  || '#888888',
    requires_approval: body.tier === 'CRITICAL',
    raw:               body
  }
}];

// Log low-risk event quietly to PostgreSQL via FraudShield API
const d = $input.first().json;
return [{ json: { status: 'logged_quietly', incident_id: d.incident_id, tier: d.tier, risk_score: d.risk_score } }];

// Combined: Call Ollama LLM + build incident log in one step
const incident = $input.first().json;
const now = new Date().toISOString();

let llmSummary = `Automated analysis: ${incident.tier} threat detected with score ${incident.risk_score}/100. Verdict: ${incident.verdict}. Immediate human review required.`;

try {
  const prompt = `You are a senior fraud analyst at Barclays. Risk Score: ${incident.risk_score}/100. Tier: ${incident.tier}. Verdict: ${incident.verdict}. Top Indicators: ${(incident.top_indicators || []).join(', ')}. Write a 2-sentence professional incident summary for the security team.`;
  const resp = await fetch('http://localhost:11434/api/generate', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'llama3', prompt: prompt, stream: false }),
    signal: AbortSignal.timeout(8000)
  });
  if (resp.ok) {
    const data = await resp.json();
    if (data.response) llmSummary = data.response.trim();
  }
} catch(e) {
  // Ollama offline — use automated fallback (no crash)
}

return [{
  json: {
    ...incident,
    llm_summary: llmSummary,
    audit_trail: `[${now}] FraudShield detected ${incident.tier} threat. Score: ${incident.risk_score}/100.\n\uD83E\uDD16 LLM Analysis: ${llmSummary}`
  }
}];

// Build HIGH tier Slack-style notification
const d = $input.first().json;
const indicators = (d.top_indicators || []).slice(0, 3).join(' | ');

return [{
  json: {
    ...d,
    slack_message: `*HIGH Risk Email Detected*\n*Score:* ${d.risk_score}/100  *Tier:* ${d.tier}\n*Verdict:* ${d.verdict}  *Action:* ${d.outlook_action}\n*AI Summary:* ${d.llm_summary}\n*Top Indicators:* ${indicators}\n*Incident ID:* ${d.incident_id}`,
    notification_type: 'HIGH'
  }
}];

// Email would be sent to security team in production.
// For demo: output the full approval email + approval URL to the execution.
const d = $input.first().json;
console.log('=== CRITICAL INCIDENT ALERT ===');
console.log('Incident ID:', d.incident_id);
console.log('Risk Score:', d.risk_score + '/100');
console.log('LLM Summary:', d.llm_summary);
console.log('APPROVE URL:', d.approve_url);
console.log('REJECT URL:', d.reject_url);
console.log('================================');
return [{ json: { ...d, email_status: 'logged_to_console_for_demo', approve_url: d.approve_url, reject_url: d.reject_url } }];

// In production this would post to Slack/Teams.
// For demo: log the HIGH risk notification to the execution output.
const d = $input.first().json;
console.log('=== HIGH RISK INCIDENT NOTIFICATION ===');
console.log('Incident ID :', d.incident_id);
console.log('Tier        :', d.tier);
console.log('Risk Score  :', d.risk_score + '/100');
console.log('Verdict     :', d.verdict);
console.log('LLM Summary :', d.llm_summary);
console.log('Indicators  :', (d.top_indicators || []).join(' | '));
console.log('=======================================');
return [{ json: { ...d, notification_status: 'logged_for_demo', notification_type: 'HIGH' } }];

// QUARANTINE CONFIRMED — send feedback to FraudShield PostgreSQL
const incident = $('Merge LLM + Incident').first().json;
const query    = $input.first().json.query;
const now      = new Date().toISOString();

return [{
  json: {
    ...incident,
    action_taken:            'QUARANTINE_CONFIRMED',
    analyst_decision:        'QUARANTINE',
    analyst_decision_at:     now,
    feedback_for_model:      'PHISHING',
    audit_trail:             incident.audit_trail + ` [${now}] Human analyst APPROVED quarantine.`,
    feedback_payload: {
      prediction_id: incident.prediction_id,
      user_verdict:  'PHISHING',
      model_verdict: incident.verdict,
      model_score:   incident.risk_score,
      notes:         `n8n workflow: analyst confirmed QUARANTINE for incident ${incident.incident_id}`
    }
  }
}];

// FALSE POSITIVE — send correction to FraudShield retraining queue
const incident = $('Merge LLM + Incident').first().json;
const now      = new Date().toISOString();

return [{
  json: {
    ...incident,
    action_taken:        'FALSE_POSITIVE',
    analyst_decision:    'SAFE',
    analyst_decision_at: now,
    feedback_for_model:  'LEGITIMATE',
    audit_trail:         incident.audit_trail + ` [${now}] Human analyst REJECTED — false positive. Queued for retraining.`,
    feedback_payload: {
      prediction_id: incident.prediction_id,
      user_verdict:  'LEGITIMATE',
      model_verdict: incident.verdict,
      model_score:   incident.risk_score,
      notes:         `n8n workflow: analyst marked FALSE POSITIVE for incident ${incident.incident_id}`
    }
  }
}];

// Final audit entry — log everything to console and build summary
const d = $input.first().json;
const now = new Date().toISOString();

console.log('=== FraudShield Audit ===');
console.log(JSON.stringify({
  incident_id:      d.incident_id,
  tier:             d.tier,
  risk_score:       d.risk_score,
  action_taken:     d.action_taken,
  analyst_decision: d.analyst_decision,
  logged_at:        d.logged_at,
  decided_at:       d.analyst_decision_at,
  llm_summary:      d.llm_summary,
  audit_trail:      d.audit_trail
}, null, 2));

return [{ json: { ...d, final_audit_at: now, workflow_complete: true } }];

const d = $input.first().json;
const now = new Date().toISOString();

console.log('=== FraudShield False Positive Logged ===');
console.log(JSON.stringify({
  incident_id:      d.incident_id,
  action_taken:     d.action_taken,
  audit_trail:      d.audit_trail,
  retraining_note:  'Correction queued for model retraining'
}, null, 2));

return [{ json: { ...d, final_audit_at: now, workflow_complete: true, retraining_queued: true } }];
